import { dummyProducts } from "@/lib/dummyData";
import Image from "next/image";
import React from "react";
import AddToCart from "../cart/AddToCart";

const ItemCard = () => {
  return (
    <>
      <main className="max-w-full h-full flex relative overflow-y-hidden">
        <div className="w-full m-4 grid flex items-start justify-center gap-4 gap-y-0 sm:grid-cols-1 md:grid-cols-2 lg:grid-cols-3 overflow-y-scroll">
          {dummyProducts.map((products) => (
            <div
              className="w-full h-60 flex flex-row justify-start rounded-lg bg-[#fff]"
              key={products.id}
            >
              <div className="md:w-2/5 shrink-0">
                <Image
                  key={products.id}
                  src={products.imageUrl}
                  width={150}
                  height={150}
                  alt="image"
                  className="object-contain h-full w-full"
                />
              </div>
              <div className="flex flex-col">
                <div className="py-5">
                  <h3 className="md:text-xl m-0 self-start text-[#5e5e5e]">
                    {products.productName}
                  </h3>
                  <span className="text-sm font-bold text-[#216c58]">
                    Price: ₱{products.price}
                  </span>
                </div>
                {/* <p className="text-sm pt-5 ml-5 mr-5">{products.description}</p> */}
                <div className="flex self-stretch items-center m-3 mt-auto justify-between">
                  <div className="flex flex-row justify-between">
                    <button >
                      <span className="text-sm font-bold text-gray-700 dark:text-white">
                        {products.quantity}
                      </span>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </main>
    </>
  );
};
export default ItemCard;
